#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <limits.h>

int minCoins(int *coins, int n, int amount) {
    int *dp = (int *)malloc((amount + 1) * sizeof(int));
    for (int i = 0; i <= amount; ++i) dp[i] = INT_MAX;
    dp[0] = 0;
    for (int i = 1; i <= amount; ++i) {
        for (int j = 0; j < n; ++j) {
            if (coins[j] <= i && dp[i - coins[j]] != INT_MAX) {
                int cand = dp[i - coins[j]] + 1;
                if (cand < dp[i]) dp[i] = cand;
            }
        }
    }
    int res = (dp[amount] == INT_MAX) ? -1 : dp[amount];
    free(dp);
    return res;
}

int main() {
    int T;
    if (scanf("%d\n", &T) != 1) return 0;
    char line[256];
    for (int tc = 0; tc < T; ++tc) {
        if (!fgets(line, sizeof(line), stdin)) break;
        line[strcspn(line, "\n")] = '\0';
        int coins[12];
        int n = 0;
        char *tok = strtok(line, ",");
        while (tok) {
            while (*tok == ' ') ++tok;
            coins[n++] = atoi(tok);
            tok = strtok(NULL, ",");
        }
        long long amtLL;
        scanf("%lld\n", &amtLL);
        int ans = minCoins(coins, n, (int)amtLL);
        printf("%d\n", ans);
    }
    return 0;
}

