// COMPLETE, COMPILABLE C++ code
#include <bits/stdc++.h>
using namespace std;

int minCoins(const vector<int>& coins, int amount) {
    const int INF = 1e9;
    vector<int> dp(amount + 1, INF);
    dp[0] = 0;
    for (int i = 1; i <= amount; ++i) {
        for (int c : coins) {
            if (c <= i && dp[i - c] != INF) {
                dp[i] = min(dp[i], dp[i - c] + 1);
            }
        }
    }
    return dp[amount] == INF ? -1 : dp[amount];
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; string line;
    if (!(cin >> T)) return 0;
    getline(cin, line); // consume endline
    while (T--) {
        getline(cin, line);
        vector<int> coins;
        string token;
        stringstream ss(line);
        while (getline(ss, token, ',')) {
            while (!token.empty() && token.front() == ' ') token.erase(token.begin());
            if (!token.empty()) coins.push_back(stoi(token));
        }
        int amount; cin >> amount; getline(cin, line); // consume endline
        cout << minCoins(coins, amount) << '\n';
    }
    return 0;
}

