// COMPLETE, COMPILABLE Java code
import java.io.*;
import java.util.*;

public class Main {
    private static int minCoins(int[] coins, int amount) {
        final int INF = Integer.MAX_VALUE / 2;
        int[] dp = new int[amount + 1];
        Arrays.fill(dp, INF);
        dp[0] = 0;
        for (int i = 1; i <= amount; i++) {
            for (int c : coins) {
                if (c <= i && dp[i - c] + 1 < dp[i]) {
                    dp[i] = dp[i - c] + 1;
                }
            }
        }
        return dp[amount] == INF ? -1 : dp[amount];
    }

    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        for (int t = 0; t < T; t++) {
            String coinLine = br.readLine();
            String[] parts = coinLine.split(",");
            int[] coins = new int[parts.length];
            for (int i = 0; i < parts.length; i++) {
                coins[i] = Integer.parseInt(parts[i].trim());
            }
            int amount = Integer.parseInt(br.readLine().trim());
            System.out.println(minCoins(coins, amount));
        }
    }
}

